import path from "node:path";
//#region extensions/qa-lab/src/cli-paths.ts
function resolveRepoRelativeOutputDir(repoRoot, outputDir) {
	if (!outputDir) return;
	if (path.isAbsolute(outputDir)) throw new Error("--output-dir must be a relative path inside the repo root.");
	const resolved = path.resolve(repoRoot, outputDir);
	const relative = path.relative(repoRoot, resolved);
	if (relative.startsWith("..") || path.isAbsolute(relative)) throw new Error("--output-dir must stay within the repo root.");
	return resolved;
}
